import{_ as e,o as r,c as o,ag as i}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq/index.md","filePath":"faq/index.md"}'),t={name:"faq/index.md"};function h(n,a,l,d,s,c){return r(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="基础问题" tabindex="-1">基础问题 <a class="header-anchor" href="#基础问题" aria-label="Permalink to &quot;基础问题&quot;">​</a></h2><h3 id="xhsops-是什么" tabindex="-1">XHSOps 是什么？ <a class="header-anchor" href="#xhsops-是什么" aria-label="Permalink to &quot;XHSOps 是什么？&quot;">​</a></h3><p>一个帮你管理小红书内容创作的 CLI 工具。它把写笔记这件事变成标准化的流程，所有内容都存在文件里，方便回顾和复用。</p><h3 id="我不会编程能用吗" tabindex="-1">我不会编程能用吗？ <a class="header-anchor" href="#我不会编程能用吗" aria-label="Permalink to &quot;我不会编程能用吗？&quot;">​</a></h3><p>能。只需要会复制粘贴命令行就行。剩下的让 AI 来做。</p><h3 id="这个工具是免费的吗" tabindex="-1">这个工具是免费的吗？ <a class="header-anchor" href="#这个工具是免费的吗" aria-label="Permalink to &quot;这个工具是免费的吗？&quot;">​</a></h3><p>免费，开源。现在免费，以后也免费。</p><hr><h2 id="工作流问题" tabindex="-1">工作流问题 <a class="header-anchor" href="#工作流问题" aria-label="Permalink to &quot;工作流问题&quot;">​</a></h2><h3 id="quick、trend、campaign-有什么区别" tabindex="-1">Quick、Trend、Campaign 有什么区别？ <a class="header-anchor" href="#quick、trend、campaign-有什么区别" aria-label="Permalink to &quot;Quick、Trend、Campaign 有什么区别？&quot;">​</a></h3><ul><li><strong>Quick</strong>：临时起意，想写一篇笔记</li><li><strong>Trend</strong>：追热点，想蹭流量</li><li><strong>Campaign</strong>：做系列，做月度规划</li></ul><p>简单说：一篇 vs 蹭热点 vs 做系列。</p><h3 id="我只想写一篇-为什么还要走流程" tabindex="-1">我只想写一篇，为什么还要走流程？ <a class="header-anchor" href="#我只想写一篇-为什么还要走流程" aria-label="Permalink to &quot;我只想写一篇，为什么还要走流程？&quot;">​</a></h3><p>不走流程也可以，但内容就散落在聊天记录里，下次想改都找不到。</p><p>走流程的好处：写过的内容能回顾、经验能积累、AI 以后能帮你写得更好。</p><h3 id="为什么-brand-没填完不能开始" tabindex="-1">为什么 brand 没填完不能开始？ <a class="header-anchor" href="#为什么-brand-没填完不能开始" aria-label="Permalink to &quot;为什么 brand 没填完不能开始？&quot;">​</a></h3><p>因为后面写笔记、审笔记都需要 brand 作为参考。brand 没定，AI 写出来的东西容易跑偏。</p><p>先花 5 分钟把 brand 填好，后面省心。</p><hr><h2 id="技术问题" tabindex="-1">技术问题 <a class="header-anchor" href="#技术问题" aria-label="Permalink to &quot;技术问题&quot;">​</a></h2><h3 id="为什么要用-placeholder" tabindex="-1">为什么要用 <code>&lt;placeholder&gt;</code>？ <a class="header-anchor" href="#为什么要用-placeholder" aria-label="Permalink to &quot;为什么要用 `&lt;placeholder&gt;`？&quot;">​</a></h3><p>为了把「没完成」变成显式状态。系统会检查它，没填完就不让你进下一阶段。</p><p>相当于有人帮你盯着：嘿，这儿还没填完呢。</p><h3 id="command-prompt-spec-有什么区别" tabindex="-1">command / prompt / spec 有什么区别？ <a class="header-anchor" href="#command-prompt-spec-有什么区别" aria-label="Permalink to &quot;command / prompt / spec 有什么区别？&quot;">​</a></h3><ul><li><strong>spec</strong>：规则文档（笔记应该怎么写）</li><li><strong>command</strong>：操作指令（怎么执行工作流）</li><li><strong>prompt</strong>：提示词模板（AI 怎么输出）</li></ul><p>不用深究会用就行。</p><h3 id="publish-为什么不放在-xhsops" tabindex="-1">publish 为什么不放在 <code>.xhsops/</code>？ <a class="header-anchor" href="#publish-为什么不放在-xhsops" aria-label="Permalink to &quot;publish 为什么不放在 `.xhsops/`？&quot;">​</a></h3><p>因为 <code>.xhsops/</code> 是工作区，publish 是最终要发出去的成品。成品单独放，方便你直接复制粘贴到小红书后台。</p><hr><h2 id="经验沉淀" tabindex="-1">经验沉淀 <a class="header-anchor" href="#经验沉淀" aria-label="Permalink to &quot;经验沉淀&quot;">​</a></h2><h3 id="为什么要-archive" tabindex="-1">为什么要 archive？ <a class="header-anchor" href="#为什么要-archive" aria-label="Permalink to &quot;为什么要 archive？&quot;">​</a></h3><p>把「做完」变成「经验」。每次 archive 后，内容会回流到 knowledge/ 目录，AI 下次写笔记时会自动参考这些经验。</p><h3 id="我能不能跳过-archive" tabindex="-1">我能不能跳过 archive？ <a class="header-anchor" href="#我能不能跳过-archive" aria-label="Permalink to &quot;我能不能跳过 archive？&quot;">​</a></h3><p>可以。但你损失的不仅是一个命令，而是未来的 AI 加持。长期来看亏的是自己。</p><hr><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="支持-windows-吗" tabindex="-1">支持 Windows 吗？ <a class="header-anchor" href="#支持-windows-吗" aria-label="Permalink to &quot;支持 Windows 吗？&quot;">​</a></h3><p>目前推荐 macOS 或 Linux。Windows 可以用 WSL，或者等原生支持。</p><h3 id="可以用来运营其他平台吗" tabindex="-1">可以用来运营其他平台吗？ <a class="header-anchor" href="#可以用来运营其他平台吗" aria-label="Permalink to &quot;可以用来运营其他平台吗？&quot;">​</a></h3><p>目前专门为小红书优化。工作流思路通用，但字段和规则是小红书特定的。</p>',41)])])}const b=e(t,[["render",h]]);export{u as __pageData,b as default};
